def is_valid_age(age):
    assert isinstance(age, int), "Yaş bir tamsayı olmalıdır."
    assert 0 <= age <= 120, "Yaş 0 ile 120 arasında olmalıdır."
    return True

def process_user_profile(username, age, email):
    assert isinstance(username, str) and len(username) > 0, "Kullanıcı adı boş olmayan bir string olmalıdır."
    assert is_valid_age(age), "Geçersiz yaş değeri."
    assert isinstance(email, str) and "@" in email and "." in email, "E-posta geçerli bir formatta olmalıdır."

    print(f"Kullanıcı Profili Oluşturuldu: {username}, {age}, {email}")

if __name__ == "__main__":
    # Geçerli örnekler
    try:
        process_user_profile("Alice", 30, "alice@example.com")
        process_user_profile("Bob", 18, "bob.smith@company.net")
        print("\nTüm geçerli profiller başarıyla işlendi.")
    except AssertionError as e:
        print(f"Geçerli örnekler için hata: {e}")

    # Geçersiz örnekler
    print("\n--- Geçersiz Örnekler ---")
    try:
        process_user_profile("", 25, "test@test.com")
    except AssertionError as e:
        print(f"Hata yakalandı (boş kullanıcı adı): {e}")

    try:
        process_user_profile("Charlie", -5, "charlie@example.com")
    except AssertionError as e:
        print(f"Hata yakalandı (negatif yaş): {e}")

    try:
        process_user_profile("David", 150, "david@example.com")
    except AssertionError as e:
        print(f"Hata yakalandı (çok yüksek yaş): {e}")

    try:
        process_user_profile("Eve", "yirmi", "eve@example.com")
    except AssertionError as e:
        print(f"Hata yakalandı (yaş string): {e}")

    try:
        process_user_profile("Frank", 40, "frank_at_example.com")
    except AssertionError as e:
        print(f"Hata yakalandı (geçersiz e-posta): {e}")

    try:
        process_user_profile("Grace", 22, 123)
    except AssertionError as e:
        print(f"Hata yakalandı (e-posta sayı): {e}")
